// Bepaalt of de bot moet reageren en maakt het bericht klaar voor de agent.
const instellingen = $('Instellingen').first().json;
const update = $('Telegram Trigger').first().json;
const msg = update.message;

if (!msg || !msg.text) { return []; }

const chatId = String(msg.chat.id);
const allowed = String(instellingen.allowedChatIds || '')
  .split(',').map(s => s.trim()).filter(Boolean);

// Nog geen whitelist ingevuld? Toon dan het chat-id, zodat je het kunt invullen.
if (allowed.length === 0) {
  return [{ json: { mode: 'direct', chatId, antwoord: `Hoi! Dit chat-id is: ${chatId}\n\nZet dit id in de node \"Instellingen\" (veld allowedChatIds) van de workflow \"Huishoudbot\" en sla de workflow op. Daarna werk ik alleen nog in deze chat.` } }];
}

if (!allowed.includes(chatId)) { return []; }

let text = msg.text.trim();
const isPrivate = msg.chat.type === 'private';
const botUser = String(instellingen.botUsername || '').replace('@', '').toLowerCase();
const mentioned = botUser !== '' && text.toLowerCase().includes('@' + botUser);
const isCommand = text.startsWith('/');
const isReplyToBot = !!(msg.reply_to_message && msg.reply_to_message.from && msg.reply_to_message.from.is_bot);

// In de groep alleen reageren op /commando's, @mentions en replies op de bot
if (!isPrivate && !mentioned && !isCommand && !isReplyToBot) { return []; }

if (mentioned) {
  text = text.replace(new RegExp('@' + botUser, 'ig'), '').trim();
}

if (/^\/(start|help)(@\w+)?$/i.test(text)) {
  const help = [
    'Ik ben jullie huishoudbot 🤖',
    '',
    'Praat gewoon Nederlands tegen me, bijvoorbeeld:',
    '• zet melk en eieren op de boodschappenlijst',
    '• wat staat er op de lijst?',
    '• streep melk maar door',
    '• wat eten we vandaag?',
    '• we eten vanavond lasagne',
    '• is er kip in de aanbieding?',
    '',
    'In de groep: noem me met @' + (botUser || 'botnaam') + ' of antwoord op een bericht van mij.',
  ].join('\n');
  return [{ json: { mode: 'direct', chatId, antwoord: help } }];
}

if (text === '') { return []; }

const afzender = msg.from ? (msg.from.first_name || msg.from.username || 'onbekend') : 'onbekend';
return [{ json: { mode: 'agent', chatId, text, afzender } }];
